package com.hospital.management.controller.appointment;import org.junit.jupiter.api.Test;import java.nio.file.*;import static org.junit.jupiter.api.Assertions.*;
class AppointmentJavaScriptTest {private String script()throws Exception{return Files.readString(Path.of("src/main/webapp/assets/js/appointments.js"));}private String jsp()throws Exception{return Files.readString(Path.of("src/main/webapp/WEB-INF/views/appointments/form.jsp"));}@Test void endpointUsesContextPathProvidedByJsp()throws Exception{assertTrue(jsp().contains("data-endpoint=\"${pageContext.request.contextPath}/appointments/slots\""));assertTrue(script().contains("slots.dataset.endpoint"));}@Test void emptyResultDisplaysNoAvailabilityMessage()throws Exception{assertTrue(script().contains("No available slots for this doctor on the selected day"));}@Test void fetchFailureDisplaysSafeError()throws Exception{String js=script();assertTrue(js.contains("if (!response.ok)"));assertTrue(js.contains("Available times could not be loaded. Please try again."));assertFalse(js.contains("error.stack"));}}
